INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1001, 1, 0, 1.4, "春咲 ひより", 0, 2, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 1, 0, "お！\nあそこに困ってそうな人発見！", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1002, 1, 0, 1.4, "草野 優衣", 0, 2, "わ、わたし、\nなに言ってるんだろ\nあはは…", "みんなみたいに\nわたしも強くならなきゃ", 1, 0, "大切な人を\n守れるようになりたい…って", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1003, 1, 0, 1.4, "士条 怜", 0, 2, "少しは磨かれると思いますよ。", "フェンシングを始めてみては？", 1, 0, "キミに必要な集中力と感性が", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1004, 1, 0, 1.5, "穂高 みそぎ", 0, 2, "みそぎはねぇ、\nかくれんぼやりたい！", "ねぇ、にいちゃん！", 1, 0, "今日はなにして遊ぶ？", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1006, 1, 0, 1.4, "風宮 あかり", 0, 2, "私といっしょに…\nいかない？", "風宮あかりです", 1, 0, "ねぇ…", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1007, 1, 0, 1.5, "出雲 宮子", 0, 2, "食べ物の恨みは怖いのー", "出雲宮子なのー", 1, 0, "プリンたべたいのー", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1008, 1, 0, 1.4, "虹村 雪", 0, 2, "いいよ。\n見られることは運命さ…", "ボクは虹村雪。", 1, 0, "キミもボクの美貌に\n吸い寄せられたんだね。", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1009, 1, 0, 1.4, "柊杏奈", 0, 2, "人呼んで「疾風の冥姫」!!", "フッ…聞いて後悔するがいい！", 1, 0, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1010, 1, 0, 1.5, "姫宮 真歩", 0, 2, "ほんまおおきにやわ～♪", "マホマホ王国のプリンセス、\nまほ姫どす", 1, 0, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1011, 1, 0, 1.4, "衣之咲 璃乃", 0, 2, "ここで会ったが\n100年目～！", "衣之咲璃乃です！", 1, 0, "生き別れたお兄ちゃんを探して\n三千世界！", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1012, 1, 0, 1.4, "柏崎 初音", 0, 2, "…って、お願い！\n誰にも言わないでおいて～！", "私はハツネ、\n結構強いんだよ。\nきらーん☆", 1, 0, "ち、超能力って…\n何のことかな～？", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1016, 1, 0, 1.4, "美波 鈴奈", 0, 2, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", "ちょす！\n美波鈴奈だよ～♪", 1, 0, "一応カリスマ読モJKやってまっす！", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1017, 1, 0, 1.4, "喜屋武 香織", 0, 2, "でも、沖縄もとってもいいとこさー", "はいたーい。\n喜屋武香織さー。", 1, 0, "東京は遊園地みたいなところさー", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1018, 1, 0, 1.4, "支倉 伊緒", 0, 2, "イオちゃんって呼んでね。", "支倉伊緒です。", 1, 0, "先生って呼ばれるのは\nくすぐったいから", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1020, 1, 0, 1.5, "茜 ミミ", 0, 2, "ミミをおいてかないでぇ～", "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 1, 0, "あ！/\お兄ちゃ～ん\nまってよ～", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1021, 1, 0, 1.5, "栗林 くるみ", 0, 2, "ふぇぇぇぇぇん……", "あ…あの…えっと…\n栗…林…くるみ…です……", 1, 0, "あの……\nふぇ……", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1022, 1, 0, 1.4, "風宮 より", 0, 2, "なんてありがとうございます！", "風宮よりです。\nあああああ！", 1, 0, "こんな私に貴重な時間を\n割いていただき、", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1023, 1, 0, 1.5, "北条 綾音", 0, 2, "私こっち行きたいー\nね、早く早くー", "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 1, 0, "おにいちゃんどこいくの？\nえ？", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1025, 1, 0, 1.4, "天野 すずめ", 0, 2, "これて何か違う…\nあああすみません！", "わっ…わっ…私、\n天野すずめといいます！", 1, 0, "ふ、不束者ですが\nどうぞ末永く…って、", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1027, 1, 0, 1.4, "倉石 恵理子", 0, 2, "離しませんわ………\n絶対に…!!", "……クスクス…私は\n…倉石恵理子……", 1, 0, "あなたは…運命の……\n伴侶……", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1028, 1, 0, 1.4, "佐々木 咲恋", 0, 2, "…そうでしょ？？", "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 1, 0, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1029, 1, 0, 1.4, "桜井 望", 0, 2, "あはは、\n私もまだまだだなぁ～", "桜井望だよ！\nよろしくねっ", 1, 0, "ぇっと…\nキミ、私のこと知らないの?!", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1030, 1, 0, 1.4, "ニノン・ジュベール", 0, 2, "ショーグン、\nワタシと一緒に天下統一デース！", "デケデケデンっ！", 1, 0, "初めまして、\n私はニノン・ジュベール申すデス！", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1031, 1, 0, 1.4, "上喜 しのぶ", 0, 2, "おかしいですね……", "上喜しのぶです。\n手元のドクロが父です。", 1, 0, "でもって私の隣にいるのが……\nえ、見えない？", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1033, 1, 0, 1.5, "野戸まひる", 0, 2, "そう、\nオラのボケに突っ込める相方が…！", "目指すはビッグな\nお笑い芸人だっぺ！", 1, 0, "けんども\nそれには足りないモンが…", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1034, 1, 0, 1.4, "綾瀬 ゆかり", 0, 2, "ちょ\nちょっと一杯飲んできます…！", "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 1, 0, "ちょっと緊張しちゃって…", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1036, 1, 0, 1.5, "氷川 鏡華", 0, 2, "これ以上お話しすることは…\nないです！", "氷川鏡華…です", 1, 0, "知らない人とは話しちゃいけないので", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1038, 1, 0, 1.4, "柏崎 栞", 0, 2, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", "柏崎…栞です。", 1, 0, "……あ、アラーム。", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1040, 1, 0, 1.4, "双葉 碧", 0, 2, "野に咲く花が、\n唯一の話相手です。", "ふ、双葉碧です。", 1, 0, "私、一人も友達がいなくて……", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1042, 1, 0, 1.4, "三角 千歌", 0, 2, "そう思っています。", "三角千歌です。", 1, 0, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1043, 1, 0, 1.4, "安芸 真琴", 0, 2, "う、疑ってすまなかったな…", "安芸真琴だ。", 1, 0, "あぁ？\nお前のそいつの仲間か？", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1044, 1, 0, 1.4, "イリヤ・オーンスタイン", 0, 2, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", "わらわこそは夜を総べる者！", 1, 0, "生けとし生ける全ての者よ！", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1045, 1, 0, 1.4, "遠見 空花", 0, 2, "ｌク、クウカに何かご用ですか!?", "そこで騎士は妖精を乱暴に……", 1, 0, "ぐふふふふ……はっ！", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1046, 1, 0, 1.4, "宮坂たまき", 0, 2, "う～ん…\n猫ってホントに最高にゃ～♪", "宮坂たまきにゃ♪\n猫はいいにゃよ？", 1, 0, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1048, 1, 0, 1.4, "大神 美冬", 0, 2, "…と思ったら\nバイトの時間だ！\nまたあとでね！", "大神美冬よ！", 1, 0, "それでは早速クエストに…", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1049, 1, 0, 1.4, "星野静流", 0, 2, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", "星野静流だよ！", 1, 0, "クエストもバトルも\n掃除も洗濯も", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1050, 1, 0, 1.5, "玉泉美咲", 0, 2, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", "アタシは玉泉美咲。", 1, 0, "見ての通りの\nセクシー美少女で", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1052, 1, 0, 1.4, "リマ", 0, 2, "？？？？", "？？？", 1, 0, "？？？？", 0, 1, 0);
