INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1059, 1, 0, 1.5, "コッコロ", 0, 2, "そ、そこまでいうなら\nもらってやる", "モニカ・ヴァイスヴィントだ。", 1, 0, "菓子でつろうなどと\n稚拙な策を……", 0, 1, 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1060, 1, 0, 1.5, "キャル", 0, 2, "そ、そこまでいうなら\nもらってやる", "モニカ・ヴァイスヴィントだ。", 1, 0, "菓子でつろうなどと\n稚拙な策を……", 0, 1, 0);
